const API_BASE = "http://localhost:8080/api";
async function request(path, options = {}) {
  const raw = localStorage.getItem("zenelait-auth");
  let token = null;
  if (raw) {
    try {
      token = JSON.parse(raw).accessToken;
    } catch {}
  }
  const res = await fetch(`${API_BASE}${path}`, {
